mapper.select:
select t1.* from tag t1
inner join post_tag t2 on t1.id = t2.tag_id and t2.post_id = #{postId}
where t1.delete_time is null and t2.delete_time is null;

select t1.* from post t1
inner join post_tag t2 on t1.id = t2.post_id and t2.tag_id = #{tagId}
where t1.delete_time is null and t2.delete_time is null;

select count(t1.id) from post t1
inner join post_tag t2 on t1.id = t2.post_id and t2.tag_id = #{tagId}
where t1.status = 1 and t1.delete_time is null and t2.delete_time is null
